const body = $json.body || $json;
if (!body.phone) { throw new Error('phone is required'); }
if (!body.template_name) { throw new Error('template_name is required'); }
const languageCode = body.language_code || 'it';
const phoneDigits = String(body.phone || '').replace(/\D/g, '');
const phone = body.phone.startsWith('+') ? body.phone : (phoneDigits ? `+${phoneDigits}` : body.phone);
let components = [];
if (Array.isArray(body.components)) { components = body.components; }
else if (Array.isArray(body.body_params)) { components = [{ type: 'body', parameters: body.body_params.map(p => ({ type: 'text', text: String(p) })) }]; }
return [{ json: { phone, template_name: body.template_name, language_code: languageCode, components } }];

const item = $input.first().json;
if (!item.WA_PHONE_NUMBER_ID) { throw new Error('WA_PHONE_NUMBER_ID missing from DataTable'); }
const payload = { messaging_product: 'whatsapp', to: item.phone, type: 'template', template: { name: item.template_name, language: { code: item.language_code } } };
if (Array.isArray(item.components) && item.components.length > 0) { payload.template.components = item.components; }
return [{ json: { wa_phone_number_id: item.WA_PHONE_NUMBER_ID, phone: item.phone, template_name: item.template_name, payload } }];

const waResponse = $json;
const msgId = waResponse.messages?.[0]?.id ?? null;
const contact = waResponse.contacts?.[0] ?? {};
const phoneFromWebhook = $node["Parse Body"].json.phone;
const status = msgId ? 'sent' : 'error';
const error = waResponse.error?.message ?? null;
return [{ json: { status, message_id: msgId, to: phoneFromWebhook, wa_id: contact.wa_id ?? null, error, raw: waResponse } }];

const waResp = $json;
const body = $node["Webhook - Send Template"].json.body || {};
const toPhone = body.phone || null;
let msgText = 'TEMPLATE: ' + (body.template_name || 'unknown');
if (Array.isArray(body.body_params) && body.body_params.length) { msgText += ' | params: ' + body.body_params.join(', '); }
const waId = waResp.contacts?.[0]?.wa_id ?? null;
const msgId = waResp.messages?.[0]?.id ?? null;
let status = waResp.status || (waResp.messages && waResp.messages[0] && waResp.messages[0].status) || null;
if (!status) {
  status = msgId ? 'sent' : (waResp.error ? 'error' : null);
}
const now = new Date();
const fmt = new Intl.DateTimeFormat('sv-SE', { timeZone: 'Europe/Rome', year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false });
const parts = fmt.formatToParts(now);
const get = (type) => { const found = parts.find(p => p.type === type); return found && found.value ? found.value : '00'; };
const ts = get('year') + '-' + get('month') + '-' + get('day') + ' ' + get('hour') + ':' + get('minute') + ':' + get('second');
return [{ json: { wa_id: waId, from_phone: null, to_phone: toPhone, direction: 'outgoing', status, message: msgText, timestamp: ts } }];
